static void lud_diagonal(float *m, int matrix_dim, int offset)
{
  int i,j;
  float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset*matrix_dim+offset;
  for(i=0; i < BLOCK_SIZE; i++){
    shadow[i][0] = m[array_offset];
    for(int t=1; t < BLOCK_SIZE; t++){
      shadow[i][t]=m[array_offset+t];
    }
    array_offset += matrix_dim;
  }

  for(i=0; i < BLOCK_SIZE-1; i++) {
    for(int thread_x=0; thread_x < BLOCK_SIZE; thread_x++) {
      if (thread_x>i){
        for(j=0; j < i; j++)
          shadow[thread_x][i] -= shadow[thread_x][j]*shadow[j][i];
        shadow[thread_x][i] /= shadow[i][i];
      }
    }
    for(int thread_x=0; thread_x < BLOCK_SIZE; thread_x++) {
      if (thread_x>i){
        for(j=0; j < i+1; j++)
          shadow[i+1][thread_x] -= shadow[i+1][j]*shadow[j][thread_x];
      }
    }
  }

  array_offset = (offset+1)*matrix_dim+offset;
  for(i=1; i < BLOCK_SIZE; i++){
    m[array_offset] = shadow[i][0];
    for(int t=1; t < BLOCK_SIZE; t++){
      m[array_offset+t] = shadow[i][t];
    }
    array_offset += matrix_dim;
  }
}

static void lud_perimeter(float *m, int matrix_dim, int offset, int block_idx)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i,j, array_offset;
  int idx;

  // Load dia and perimeter blocks
  for (int thread_x=0; thread_x < BLOCK_SIZE*2; thread_x++) {
    if (thread_x < BLOCK_SIZE) {
      idx = thread_x;
      array_offset = offset*matrix_dim+offset;
      for (i=0; i < BLOCK_SIZE/2; i++){
        dia[i][idx]=m[array_offset+idx];
        array_offset += matrix_dim;
      }
      array_offset = offset*matrix_dim+offset;
      for (i=0; i < BLOCK_SIZE; i++) {
        peri_row[i][idx]=m[array_offset+(block_idx+1)*BLOCK_SIZE+idx];
        array_offset += matrix_dim;
      }
    } else {
      idx = thread_x-BLOCK_SIZE;
      array_offset = (offset+BLOCK_SIZE/2)*matrix_dim+offset;
      for (i=BLOCK_SIZE/2; i < BLOCK_SIZE; i++){
        dia[i][idx]=m[array_offset+idx];
        array_offset += matrix_dim;
      }
      array_offset = (offset+(block_idx+1)*BLOCK_SIZE)*matrix_dim+offset;
      for (i=0; i < BLOCK_SIZE; i++) {
        peri_col[i][idx] = m[array_offset+idx];
        array_offset += matrix_dim;
      }
    }
  }

  // Computation on peri_row and peri_col
  for (int thread_x=0; thread_x < BLOCK_SIZE*2; thread_x++) {
    if (thread_x < BLOCK_SIZE) { 
      idx=thread_x;
      for(i=1; i < BLOCK_SIZE; i++){
        for (j=0; j < i; j++)
          peri_row[i][idx]-=dia[i][j]*peri_row[j][idx];
      }
    } else { 
      idx=thread_x - BLOCK_SIZE;
      for(i=0; i < BLOCK_SIZE; i++){
        for(j=0; j < i; j++)
          peri_col[idx][i]-=peri_col[idx][j]*dia[j][i];
        peri_col[idx][i] /= dia[i][i];
      }
    }
  }

  // Write back results
  for (int thread_x=0; thread_x < BLOCK_SIZE*2; thread_x++) {
    if (thread_x < BLOCK_SIZE) { 
      idx=thread_x;
      array_offset = (offset+1)*matrix_dim+offset;
      for(i=1; i < BLOCK_SIZE; i++){
        m[array_offset+(block_idx+1)*BLOCK_SIZE+idx] = peri_row[i][idx];
        array_offset += matrix_dim;
      }
    } else { 
      idx=thread_x - BLOCK_SIZE;
      array_offset = (offset+(block_idx+1)*BLOCK_SIZE)*matrix_dim+offset;
      for(i=0; i < BLOCK_SIZE; i++){
        m[array_offset+idx] =  peri_col[i][idx];
        array_offset += matrix_dim;
      }
    }
  }
}

static void lud_internal(float *m, int matrix_dim, int offset, int block_x, int block_y)
{
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i;
  float sum;

  int global_row_id = offset + (block_y+1)*BLOCK_SIZE;
  int global_col_id = offset + (block_x+1)*BLOCK_SIZE;

  for(int ty=0; ty < BLOCK_SIZE; ty++){
    for(int tx=0; tx < BLOCK_SIZE; tx++){
      peri_row[ty][tx] = m[(offset+ty)*matrix_dim+global_col_id+tx];
      peri_col[ty][tx] = m[(global_row_id+ty)*matrix_dim+offset+tx];
    }
  }

  for(int ty=0; ty < BLOCK_SIZE; ty++){
    for(int tx=0; tx < BLOCK_SIZE; tx++){
      sum = 0;
      for (i=0; i < BLOCK_SIZE; i++)
        sum += peri_col[ty][i] * peri_row[i][tx];
      m[(global_row_id+ty)*matrix_dim+global_col_id+tx] -= sum;
    }
  }
}

void lud_cuda(float *m, int matrix_dim)
{
  int i=0;
  float *m_debug = (float*)malloc(matrix_dim*matrix_dim*sizeof(float));

  for (i=0; i < matrix_dim-BLOCK_SIZE; i += BLOCK_SIZE) {
      lud_diagonal(m, matrix_dim, i);

      int perimeter_blocks = (matrix_dim - i)/BLOCK_SIZE - 1;

#pragma omp parallel for default(none) shared(m, matrix_dim, i, perimeter_blocks) schedule(static)
      for (int b=0; b < perimeter_blocks; b++) {
          lud_perimeter(m, matrix_dim, i, b);
      }

      int internal_blocks = perimeter_blocks;

#pragma omp parallel for collapse(2) default(none) shared(m, matrix_dim, i, internal_blocks) schedule(static)
      for (int by=0; by < internal_blocks; by++) {
          for (int bx=0; bx < internal_blocks; bx++) {
              lud_internal(m, matrix_dim, i, bx, by);
          }
      }
  }
  lud_diagonal(m, matrix_dim, i);

  free(m_debug);
}
